@if (Products.Count == 0)
{
    <div class="empty-results">
        <p>No products found matching your criteria.</p>
    </div>
}
else
{
    <div class="product-grid">
        @foreach (var product in Products)
        {
            <ProductCard Product="product"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="OnAddToCart" />
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = [];

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@if (TotalPages > 1)
{
    <nav class="catalog-pagination" aria-label="Product pagination">
        <button class="btn-page"
                disabled="@(CurrentPage <= 1)"
                @onclick="() => GoToPage(CurrentPage - 1)">
            Previous
        </button>

        @foreach (var page in GetPageNumbers())
        {
            <button class="btn-page @(page == CurrentPage ? "active" : "")"
                    @onclick="() => GoToPage(page)">
                @page
            </button>
        }

        <button class="btn-page"
                disabled="@(CurrentPage >= TotalPages)"
                @onclick="() => GoToPage(CurrentPage + 1)">
            Next
        </button>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
        {
            return Enumerable.Range(1, TotalPages);
        }

        var start = Math.Max(1, CurrentPage - maxVisible / 2);
        var end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);
        return Enumerable.Range(start, end - start + 1);
    }
}

@if (Products.Count == 0)
