@page "/catalog"
@rendermode InteractiveServer
@using sv_4e1cc61f9f7a47abaa95dfc9201b3fd9.Components.Catalog
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>Something went wrong: @_error</p>
        <button class="btn-apply" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogFilters Categories="_categories"
                        CurrentFilter="_filter"
                        OnFiltersApplied="HandleFiltersApplied"
                        OnFiltersCleared="HandleFiltersCleared" />

        <main class="catalog-main">
            @if (_loading)
            {
                <div class="catalog-loading">
                    <p>Loading products…</p>
                </div>
            }
            else if (_result is not null)
            {
                <CatalogToolbar SortBy="@_sortBy"
                                TotalCount="_result.TotalCount"
                                Page="_result.Page"
                                PageSize="_result.PageSize"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;
    private int _totalPages;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
            _totalPages = CalcTotalPages(_result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            _totalPages = CalcTotalPages(_result);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFiltersCleared()
    {
        _filter = new(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — wire up cart service when available
        return Task.CompletedTask;
    }

    private async Task RetryAsync() => await SearchAsync();

    private static int CalcTotalPages(PagedResult<Product> result) =>
        result.PageSize > 0 ? (int)Math.Ceiling((double)result.TotalCount / result.PageSize) : 1;
}

